import {
  type DutyStation,
  type StationLink,
  type StationLinkCategory,
  type StationSummaries,
  STATION_LINK_CATEGORIES,
} from "@/types/station";

function emptyLink(category: StationLinkCategory): StationLink {
  return {
    category,
    url: "",
    originalUrl: null,
    isRemediated: false,
    remediationReason: null,
    remediatedAt: null,
    isValid: null,
    lastCheckedAt: null,
    statusCode: null,
    resolvedUrl: null,
  };
}

function emptyLinks(): DutyStation["links"] {
  return STATION_LINK_CATEGORIES.reduce(
    (acc, category) => {
      acc[category] = emptyLink(category);
      return acc;
    },
    {} as DutyStation["links"]
  );
}

export function makeStation(overrides: Partial<DutyStation> = {}): DutyStation {
  return {
    id: "test-station",
    name: "Test Station",
    city: "Laredo",
    state: "TX",
    zipCode: "78040",
    sector: "Test Sector",
    lat: 27.5,
    lng: -99.5,
    region: "Southwest",
    description: "A test station.",
    componentType: "USBP",
    facilityType: "Station",
    sourceType: "Station",
    sourceParent: "Test Sector",
    sourceUrl: null,
    positionTypes: ["BPA"],
    attributes: {
      incentiveEligible: false,
      incentiveLabel: null,
      disclaimerApplies: true,
    },
    links: emptyLinks(),
    recreation: [],
    streetAddress: null,
    streetAddress2: null,
    preciseLat: null,
    preciseLng: null,
    countyName: null,
    countyFips: null,
    placeName: null,
    placeFips: null,
    addressGeocodedAt: null,
    addressGeocodeSource: null,
    summaries: {},
    ...overrides,
  };
}

